      "shot_id": "SH10",
      "priority": "P0",
      "intent": "用俱乐部后台的电话反应，表现佐藤美咲沉默得知“彩花出事了”，并以酒杯险些滑落外化震惊。",
      "duration_sec": 5,
      "shot_type": "中近景",
      "movement": "固定机位",
      "framing_focus": "夜晚俱乐部“ルミナ”后台洗杯工作区内，佐藤美咲以正面中近景站在工作台前，垂眼用1块白色擦杯布擦拭1只透明细柄高脚杯，1部黑色手机平放在她右手侧工作台边，后台冷白工作灯与前厅暖色灯溢光混合。人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "action_intent": "首帧后，手机响起；美咲拿起黑色手机贴近耳边，屏幕朝内不可见，沉默听远端酒店服务员慌张说彩花出事了；她嘴唇闭合，握杯的手一抖，透明细柄高脚杯短暂下滑后被她及时扶稳，酒杯保持完整。",
      "emotion_intent": "震住后的克制、警觉和压住慌张的认真倾听。",
      "scene_id": "EP02_CLUB_LUMINA_BACKSTAGE",
      "scene_name": "俱乐部“ルミナ”后台内靠近吧台洗杯工作区的位置",
      "time_of_day": "夜晚",
      "primary_light_source": "俱乐部后台冷白工作灯与前厅暖色灯溢光",
      "dialogue": [
        {
          "speaker": "酒店的服务员（远端电话声音）",
          "text": "佐藤小姐，酒店这边出事了……彩花小姐出事了！",
          "purpose": "通过远端电话告知美咲彩花出事，触发她的震惊反应",
          "source": "phone",
          "listener": "佐藤美咲"
        }
      ],
      "narration": [],
      "subtitle": [
        "（电话里，慌张）佐藤小姐，酒店这边出事了……彩花小姐出事了！"
      ],
      "positive_core": "夜晚俱乐部“ルミナ”后台洗杯工作区内，佐藤美咲正面中近景站在工作台前，垂眼用1块白色擦杯布擦拭1只透明细柄高脚杯，1部黑色手机平放在她右手侧工作台边。手机响起后，她拿起手机贴近耳边，屏幕朝向自己；远端酒店服务员的电话声传来，美咲认真地听电话，一句话也没有说，闭着嘴，认真思考。听到“彩花小姐出事了”时，她握杯的手轻轻一抖，又迅速扶稳酒杯。前厅客人笑声从后台外侧传来，电话声来自手机听筒，画面不切到酒店端。人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "resolved_costume": {
        "佐藤美咲": {
          "character_id": "MISAKI_FEMALE",
          "name": "佐藤美咲",
          "costume": "深灰色姐姐旧礼服，外搭黑灰色旧短外套，低调黑色平底鞋，携带但首帧不重点展示黑色旧皮革手袋",
          "source": "episode_costume_contract",
          "is_canonical": false,
